  1→"use client";
  2→
  3→import {
  4→  hapticFeedback,
  5→  useSignal,
  6→  viewport,
  7→} from "@telegram-apps/sdk-react";
  8→import type { Signal } from "@telegram-apps/signals";
  9→import { motion, type PanInfo } from "framer-motion";
 10→import { X } from "lucide-react";
 11→import { useRouter } from "next/navigation";
 12→import { useCallback, useEffect, useState } from "react";
 13→
 14→import { getAvatarColor, getFirstLetter } from "@/components/summaries/avatar-utils";
 15→import { MOCK_SUMMARIES } from "@/components/summaries/mock-data";
 16→import { useSummaries } from "@/components/summaries/SummariesContext";
 17→import ConnectBotModal from "@/components/telegram/ConnectBotModal";
 18→import { publicEnv } from "@/lib/core/config/public";
 19→
 20→type GroupChat = {
 21→  id: string;
 22→  title: string;
 23→  subtitle: string;
 24→  photoBase64?: string;
 25→  photoMimeType?: string;
 26→  photoUrl?: string;
 27→};
 28→
 29→interface ChatItemSkeletonProps {
 30→  titleWidth?: string;
 31→  subtitleWidth?: string;
 32→}
 33→
 34→function ChatItemSkeleton({
 35→  titleWidth = "w-32",
 36→  subtitleWidth = "w-48",
 37→}: ChatItemSkeletonProps) {
 38→  return (
 39→    <div className="px-4">
 40→      <div className="flex items-center w-full py-2">
 41→        {/* Avatar Skeleton */}
 42→        <div className="pr-3">
 43→          <div className="w-12 h-12 rounded-full bg-black/5 animate-pulse" />
 44→        </div>
 45→
 46→        {/* Title and Subtitle Skeleton */}
 47→        <div className="flex-1 min-w-0 flex flex-col gap-1.5">
 48→          <div className={`${titleWidth} h-5 bg-black/5 animate-pulse rounded`} />
 49→          <div className={`${subtitleWidth} h-4 bg-black/5 animate-pulse rounded`} />
 50→        </div>
 51→      </div>
 52→    </div>
 53→  );
 54→}
 55→
 56→// Skeleton configurations for visual variety
 57→const SKELETON_CONFIGS = [
 58→  { titleWidth: "w-36", subtitleWidth: "w-52" },
 59→  { titleWidth: "w-28", subtitleWidth: "w-44" },
 60→  { titleWidth: "w-32", subtitleWidth: "w-56" },
 61→  { titleWidth: "w-24", subtitleWidth: "w-40" },
 62→  { titleWidth: "w-40", subtitleWidth: "w-48" },
 63→];
 64→
 65→function ChatListSkeleton({ count = 5 }: { count?: number }) {
 66→  return (
 67→    <>
 68→      {Array.from({ length: count }).map((_, index) => (
 69→        <ChatItemSkeleton
 70→          key={index}
 71→          titleWidth={SKELETON_CONFIGS[index % SKELETON_CONFIGS.length].titleWidth}
 72→          subtitleWidth={SKELETON_CONFIGS[index % SKELETON_CONFIGS.length].subtitleWidth}
 73→        />
 74→      ))}
 75→    </>
 76→  );
 77→}
 78→
 79→interface ChatItemProps {
 80→  chat: { id: string; title: string; subtitle?: string; photoBase64?: string; photoMimeType?: string; photoUrl?: string };
 81→  onClick: () => void;
 82→}
 83→
 84→function ChatItem({ chat, onClick }: ChatItemProps) {
 85→  const avatarColor = getAvatarColor(chat.title);
 86→  const firstLetter = getFirstLetter(chat.title);
 87→
 88→  const photoSrc = chat.photoUrl
 89→    ? chat.photoUrl
 90→    : chat.photoBase64
 91→      ? `data:${chat.photoMimeType || "image/jpeg"};base64,${chat.photoBase64}`
 92→      : null;
 93→
 94→  return (
 95→    <div className="relative px-4">
 96→      <button
 97→        onClick={onClick}
 98→        className="flex items-center w-full active:opacity-80 transition-opacity text-left"
 99→      >
100→        {/* Avatar */}
101→        <div className="pr-3 py-1.5">
102→          {photoSrc ? (
103→            <img
104→              src={photoSrc}
105→              alt={chat.title}
106→              className="w-12 h-12 rounded-full object-cover"
107→            />
108→          ) : (
109→            <div
110→              className="w-12 h-12 rounded-full flex items-center justify-center"
111→              style={{ backgroundColor: avatarColor }}
112→            >
113→              <span className="text-lg font-medium text-white">{firstLetter}</span>
114→            </div>
115→          )}
116→        </div>
117→
118→        {/* Title and Subtitle */}
119→        <div className="flex-1 min-w-0 flex flex-col gap-0.5 py-2.5">
120→          <p className="text-base text-black font-medium leading-5 truncate">{chat.title}</p>
121→          {chat.subtitle && (
122→            <p className="text-[13px] text-black/50 leading-4 truncate">
123→              {chat.subtitle}
124→            </p>
125→          )}
126→        </div>
127→      </button>
128→      {/* Separator */}
129→      <div className="absolute bottom-0 right-0 left-[76px] h-px">
130→        <div className="h-[0.33px] bg-black/12 w-full" />
131→      </div>
132→    </div>
133→  );
134→}
135→
136→// Tab types
137→type TabId = "groups" | "direct" | "personal" | "work";
138→
139→interface Tab {
140→  id: TabId;
141→  label: string;
142→  count: number;
143→  hasDividerAfter?: boolean;
144→}
145→
146→// Tab data will be computed dynamically
147→const getTabsData = (groupCount: number): Tab[] => [
148→  { id: "groups", label: "Groups", count: groupCount, hasDividerAfter: true },
149→  // Temporarily hidden until non-group summaries are supported.
150→  // { id: "direct", label: "Direct", count: directCount },
151→  // { id: "personal", label: "Personal", count: 0 },
152→  // { id: "work", label: "Work", count: 0 },
153→];
154→
155→
156→interface EmptyStateBannerProps {
157→  onClose: () => void;
158→  onConnectChats: () => void;
159→}
160→
161→function EmptyStateBanner({ onClose, onConnectChats }: EmptyStateBannerProps) {
162→  return (
163→    <div className="px-3 pt-1 pb-2">
164→      <div className="relative bg-black/[0.04] rounded-2xl overflow-hidden pl-4 pr-11 py-4">
165→        <div className="flex flex-col gap-3">
166→          {/* Text Content */}
167→          <div className="flex flex-col gap-0.5">
168→            <p className="text-base font-medium text-black leading-5 tracking-[-0.18px]">
169→              No summarized chats yet
170→            </p>
171→            <p className="text-[13px] text-black/50 leading-[18px] tracking-[-0.08px]">
172→              Connect your Telegram groups to start getting summaries here.
173→            </p>
174→          </div>
175→
176→          {/* Connect Button */}
177→          <div>
178→            <button
179→              onClick={onConnectChats}
180→              className="bg-black/[0.06] rounded-full px-4 py-2 active:opacity-80 transition-opacity"
181→            >
182→              <span className="text-sm font-medium text-black leading-5">
183→                Connect Chats
184→              </span>
185→            </button>
186→          </div>
187→        </div>
188→
189→        {/* Close Button */}
190→        <button
191→          onClick={onClose}
192→          className="absolute top-2 right-2 p-1 active:opacity-80 transition-opacity"
193→        >
194→          <X size={24} strokeWidth={1.5} className="text-black/40" />
195→        </button>
196→      </div>
197→    </div>
198→  );
199→}
200→
201→const MOCK_DIRECT_CHATS: GroupChat[] = [
202→  {
203→    id: "dm-1",
204→    title: "Alice Morgan",
205→    subtitle: "Discussed the token migration timeline",
206→    photoUrl: "/uifaces-popular-avatar.jpg",
207→  },
208→  {
209→    id: "dm-2",
210→    title: "Jake Wilson",
211→    subtitle: "Shared the updated deployment config",
212→    photoUrl: "/uifaces-popular-avatar-1.jpg",
213→  },
214→];
215→
216→const ACTIVE_TAB_STORAGE_KEY = "summaries_active_tab";
217→
218→export default function SummariesPage() {
219→  const router = useRouter();
220→  const safeAreaInsetTop = useSignal(
221→    viewport.safeAreaInsetTop as Signal<number>
222→  );
223→  const headerHeight = Math.max(safeAreaInsetTop || 0, 12) + 10 + 27 + 16;
224→
225→  const [isBannerDismissed, setIsBannerDismissed] = useState(false);
226→  const [activeTab, setActiveTab] = useState<TabId>(() => {
227→    // Initialize from localStorage, default to "groups"
228→    if (typeof window !== "undefined") {
229→      const saved = localStorage.getItem(ACTIVE_TAB_STORAGE_KEY);
230→      if (saved === "groups") {
231→        return saved;
232→      }
233→    }
234→    return "groups";
235→  });
236→  const [isConnectBotModalOpen, setIsConnectBotModalOpen] = useState(false);
237→  const [swipeDirection, setSwipeDirection] = useState<1 | -1>(1); // 1 = from right, -1 = from left
238→  const [isLoading, setIsLoading] = useState(true);
239→
240→  const [groupChats, setGroupChats] = useState<GroupChat[]>([]);
241→  const [isGroupsLoading, setIsGroupsLoading] = useState(true);
242→  const { summaries: cachedSummaries, setSummaries, hasCachedData } = useSummaries();
243→
244→  // Transform summaries to unique group chats format (deduplicate by title)
245→  const transformToGroupChats = (summaries: Array<{ id: string; title: string; photoBase64?: string; photoMimeType?: string; topics?: Array<{ content: string }> }>) => {
246→    const groupMap = new Map<string, GroupChat>();
247→
248→    for (const summary of summaries) {
249→      // Only keep the first (most recent) summary for each group
250→      if (!groupMap.has(summary.title)) {
251→        groupMap.set(summary.title, {
252→          id: summary.id,
253→          title: summary.title,
254→          subtitle: summary.topics?.[0]?.content || "",
255→          photoBase64: summary.photoBase64,
256→          photoMimeType: summary.photoMimeType,
257→        });
258→      }
259→    }
260→
261→    return Array.from(groupMap.values());
262→  };
263→
264→  // Initialize from cached data immediately
265→  useEffect(() => {
266→    if (hasCachedData && cachedSummaries.length > 0) {
267→      setGroupChats(transformToGroupChats(cachedSummaries));
268→      setIsGroupsLoading(false);
269→    }
270→  }, [hasCachedData, cachedSummaries]);
271→
272→  // Fetch fresh data (in background if we have cache)
273→  useEffect(() => {
274→    const fetchGroupChats = async () => {
275→      // Use mock data in development when flag is set
276→      if (publicEnv.useMockSummaries) {
277→        setSummaries(MOCK_SUMMARIES);
278→        setGroupChats(transformToGroupChats(MOCK_SUMMARIES));
279→        setIsGroupsLoading(false);
280→        return;
281→      }
282→
283→      // Only show loading if no cached data
284→      if (!hasCachedData) {
285→        setIsGroupsLoading(true);
286→      }
287→      try {
288→        const response = await fetch("/api/summaries");
289→        if (!response.ok) return;
290→        const data = await response.json();
291→        const summaries = data.summaries || [];
292→
293→        // Update context (persists to sessionStorage)
294→        setSummaries(summaries);
295→
296→        // Update list view
297→        setGroupChats(transformToGroupChats(summaries));
298→      } catch {
299→        // Silently fail - will show cached or empty state
300→      } finally {
301→        setIsGroupsLoading(false);
302→      }
303→    };
304→    fetchGroupChats();
305→  }, [setSummaries, hasCachedData]);
306→
307→  // Mock DM data (dev only, controlled by NEXT_PUBLIC_USE_MOCK_SUMMARIES)
308→  const useMockDMs = publicEnv.useMockSummaries;
309→  const directChats = useMockDMs ? MOCK_DIRECT_CHATS : [];
310→
311→  // Get tabs data and current chat list based on active tab
312→  const tabs = getTabsData(groupChats.length);
313→  const currentChatList =
314→    activeTab === "groups" ? groupChats :
315→    activeTab === "direct" ? directChats :
316→    [];
317→
318→  // Save active tab to localStorage when it changes
319→  useEffect(() => {
320→    localStorage.setItem(ACTIVE_TAB_STORAGE_KEY, activeTab);
321→  }, [activeTab]);
322→
323→  // Loading state: use real loading for groups, brief delay for other tabs
324→  useEffect(() => {
325→    if (activeTab === "groups") {
326→      setIsLoading(isGroupsLoading);
327→    } else {
328→      // Brief delay for placeholder tabs for smooth transition
329→      setIsLoading(true);
330→      const timer = setTimeout(() => setIsLoading(false), 150);
331→      return () => clearTimeout(timer);
332→    }
333→  }, [activeTab, isGroupsLoading]);
334→
335→  // Handle swipe to switch tabs
336→  const handleSwipe = useCallback(
337→    (_event: MouseEvent | TouchEvent | PointerEvent, info: PanInfo) => {
338→      const SWIPE_THRESHOLD = 50;
339→      const tabOrder: TabId[] = [
340→        "groups",
341→        // Temporarily hidden until non-group summaries are supported.
342→        // "direct",
343→        // "personal",
344→        // "work",
345→      ];
346→      const currentIndex = tabOrder.indexOf(activeTab);
347→
348→      if (info.offset.x < -SWIPE_THRESHOLD && currentIndex < tabOrder.length - 1) {
349→        // Swipe left - go to next tab (content comes from right)
350→        if (hapticFeedback.impactOccurred.isAvailable()) {
351→          hapticFeedback.impactOccurred("light");
352→        }
353→        setSwipeDirection(1);
354→        setActiveTab(tabOrder[currentIndex + 1]);
355→      } else if (info.offset.x > SWIPE_THRESHOLD && currentIndex > 0) {
356→        // Swipe right - go to previous tab (content comes from left)
357→        if (hapticFeedback.impactOccurred.isAvailable()) {
358→          hapticFeedback.impactOccurred("light");
359→        }
360→        setSwipeDirection(-1);
361→        setActiveTab(tabOrder[currentIndex - 1]);
362→      }
363→    },
364→    [activeTab]
365→  );
366→
367→  const handleChatClick = (chat: { id: string; title: string; subtitle?: string; messageCount?: number }) => {
368→    if (hapticFeedback.impactOccurred.isAvailable()) {
369→      hapticFeedback.impactOccurred("light");
370→    }
371→
372→    // Groups tab: navigate to SummaryFeed page (vertical swipe)
373→    if (activeTab === "groups") {
374→      router.push(`/telegram/summaries/feed?chatId=${chat.id}`);
375→      return;
376→    }
377→
378→    // Direct and other tabs: navigate to DirectFeed page (horizontal swipe)
379→    router.push(`/telegram/summaries/direct?chatId=${chat.id}&tab=${activeTab}`);
380→  };
381→
382→  const handleBannerClose = () => {
383→    if (hapticFeedback.impactOccurred.isAvailable()) {
384→      hapticFeedback.impactOccurred("light");
385→    }
386→    setIsBannerDismissed(true);
387→  };
388→
389→  const handleConnectChats = () => {
390→    if (hapticFeedback.impactOccurred.isAvailable()) {
391→      hapticFeedback.impactOccurred("medium");
392→    }
393→    // TODO: Navigate to connect chats flow
394→  };
395→
396→  return (
397→    <main
398→      className="text-foreground font-sans overflow-y-auto relative flex flex-col"
399→      style={{ background: "#fff", height: `calc(100vh - ${headerHeight}px)` }}
400→    >
401→      {/* Header - fixed at top */}
402→      <div
403→        className="sticky top-0 z-10"
404→        style={{ background: "#fff" }}
405→      >
406→        <div className="flex items-center px-4">
407→          <div className="flex-1 py-3">
408→            <h1 className="text-[22px] font-semibold text-black leading-7">Chat Highlights</h1>
409→          </div>
410→        </div>
411→
412→        {/* Tabs */}
413→        <div className="flex pl-4 border-b border-black/10">
414→          {tabs.map((tab, index) => (
415→            <div key={tab.id} className="flex items-center">
416→              <button
417→                onClick={() => {
418→                  if (hapticFeedback.impactOccurred.isAvailable()) {
419→                    hapticFeedback.impactOccurred("light");
420→                  }
421→                  const tabOrder: TabId[] = [
422→                    "groups",
423→                    // Temporarily hidden until non-group summaries are supported.
424→                    // "direct",
425→                    // "personal",
426→                    // "work",
427→                  ];
428→                  const currentIndex = tabOrder.indexOf(activeTab);
429→                  const targetIndex = tabOrder.indexOf(tab.id);
430→                  setSwipeDirection(targetIndex > currentIndex ? 1 : -1);
431→                  setActiveTab(tab.id);
432→                }}
433→                className={`flex items-center gap-1.5 pr-4 pb-2.5 pt-1 relative transition-colors ${
434→                  index > 0 ? "pl-4" : ""
435→                } ${activeTab === tab.id ? "text-black" : "text-black/40"}`}
436→              >
437→                <span className="text-base font-medium leading-5 tracking-[-0.176px]">{tab.label}</span>
438→                {tab.count > 0 && (
439→                  <span className="min-w-5 h-5 flex items-center justify-center text-xs font-medium rounded-full text-white bg-[#FF3B30] px-1.5">
440→                    {tab.count}
441→                  </span>
442→                )}
443→                {activeTab === tab.id && (
444→                  <div
445→                    className={`absolute bottom-0 right-3 h-[3px] rounded-t-[4px] rounded-b-[1px] bg-black ${
446→                      index > 0 ? "left-3" : "left-0"
447→                    }`}
448→                  />
449→                )}
450→              </button>
451→              {/* Vertical divider after tab if specified */}
452→              {tab.hasDividerAfter && (
453→                <div className="flex items-center self-stretch px-2">
454→                  <div className="w-px h-5 bg-black/15 rounded-[1px]" />
455→                </div>
456→              )}
457→            </div>
458→          ))}
459→        </div>
460→      </div>
461→
462→      {/* Chat List or Empty State - Swipeable */}
463→      <motion.div
464→        className="flex-1 flex flex-col"
465→        drag="x"
466→        dragConstraints={{ left: 0, right: 0 }}
467→        dragElastic={0.1}
468→        onDragEnd={handleSwipe}
469→        key={activeTab}
470→        initial={{ opacity: 0.7, x: swipeDirection * 30 }}
471→        animate={{ opacity: 1, x: 0 }}
472→        transition={{ duration: 0.2, ease: "easeOut" }}
473→      >
474→        {isLoading ? (
475→          <div className="flex-1 flex flex-col pt-2 pb-4">
476→            <ChatListSkeleton count={5} />
477→
478→            {/* Bottom padding for navigation */}
479→            <div className="h-32 shrink-0" />
480→          </div>
481→        ) : currentChatList.length === 0 ? (
482→          <div className="flex-1 flex flex-col pt-1">
483→            {!isBannerDismissed && (
484→              <EmptyStateBanner
485→                onClose={handleBannerClose}
486→                onConnectChats={handleConnectChats}
487→              />
488→            )}
489→          </div>
490→        ) : (
491→          <div className="flex-1 flex flex-col pt-2 pb-4">
492→            {currentChatList.map((chat) => (
493→              <ChatItem
494→                key={chat.id}
495→                chat={chat}
496→                onClick={() => handleChatClick(chat)}
497→              />
498→            ))}
499→
500→            {/* Bottom padding for navigation */}
501→            <div className="h-32 shrink-0" />
502→          </div>
503→        )}
504→      </motion.div>
505→
506→      {/* Connect Bot Modal */}
507→      <ConnectBotModal
508→        open={isConnectBotModalOpen}
509→        onOpenChange={setIsConnectBotModalOpen}
510→      />
511→    </main>
512→  );
513→}
