  1→"use client";
  2→
  3→import {
  4→  backButton,
  5→  hapticFeedback,
  6→  swipeBehavior,
  7→  useSignal,
  8→  viewport,
  9→} from "@telegram-apps/sdk-react";
 10→import type { Signal } from "@telegram-apps/signals";
 11→import { useRouter } from "next/navigation";
 12→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
 13→
 14→import { getAvatarColor, getFirstLetter } from "./avatar-utils";
 15→import DatePicker from "./DatePicker";
 16→
 17→export type ChatSummary = {
 18→  id: string;
 19→  title: string;
 20→  messageCount?: number;
 21→  createdAt?: string;
 22→  photoBase64?: string;
 23→  photoMimeType?: string;
 24→  topics: Array<{
 25→    id: string;
 26→    title: string;
 27→    content: string;
 28→    sources: string[];
 29→  }>;
 30→};
 31→
 32→// Source avatars component (overlapping circles)
 33→function SourceAvatars({ sources }: { sources: string[] }) {
 34→  return (
 35→    <div className="flex items-end pt-3">
 36→      <div className="flex items-center">
 37→        {sources.slice(0, 3).map((source, index) => (
 38→          <div
 39→            key={source}
 40→            className="rounded-full flex items-center justify-center text-[10px] font-medium text-white"
 41→            style={{
 42→              width: 28,
 43→              height: 28,
 44→              backgroundColor: getAvatarColor(source),
 45→              marginRight: -2,
 46→              zIndex: sources.length - index,
 47→            }}
 48→          >
 49→            {getFirstLetter(source)}
 50→          </div>
 51→        ))}
 52→      </div>
 53→    </div>
 54→  );
 55→}
 56→
 57→// Empty state for today when no summaries available
 58→function EmptyState() {
 59→  return (
 60→    <div className="flex flex-col items-center justify-center px-8 py-16">
 61→      <img
 62→        src="/dogs/dog-green.png"
 63→        alt=""
 64→        className="w-16 h-16 object-contain mb-4 opacity-60"
 65→      />
 66→      <p className="text-[15px] text-center" style={{ color: "rgba(60,60,67,0.6)" }}>
 67→        Summary for today is being created...
 68→      </p>
 69→    </div>
 70→  );
 71→}
 72→
 73→// Topic card component
 74→function TopicCard({ topic }: { topic: ChatSummary["topics"][0] }) {
 75→  return (
 76→    <div className="bg-[#F2F2F7] overflow-hidden" style={{ borderRadius: 26, padding: 16 }}>
 77→      <h2 className="font-semibold text-black pb-3" style={{ fontSize: 20, lineHeight: "24px" }}>
 78→        {topic.title}
 79→      </h2>
 80→      <p className="font-normal" style={{ fontSize: 15, lineHeight: "20px", color: "rgba(60,60,67,0.8)" }}>
 81→        {topic.content}
 82→      </p>
 83→      <SourceAvatars sources={topic.sources} />
 84→    </div>
 85→  );
 86→}
 87→
 88→// Smooth ease-out for animations
 89→const EASE_OUT = "cubic-bezier(0.0, 0.0, 0.2, 1)";
 90→
 91→// Convert ISO date string to YYYY-MM-DD format
 92→function toDateKey(isoString: string): string {
 93→  return isoString.split("T")[0];
 94→}
 95→
 96→// Group summaries by date
 97→function groupSummariesByDate(
 98→  summaries: ChatSummary[]
 99→): Map<string, ChatSummary[]> {
100→  const map = new Map<string, ChatSummary[]>();
101→
102→  for (const summary of summaries) {
103→    if (!summary.createdAt) continue;
104→    const dateKey = toDateKey(summary.createdAt);
105→    const existing = map.get(dateKey) || [];
106→    existing.push(summary);
107→    map.set(dateKey, existing);
108→  }
109→
110→  return map;
111→}
112→
113→// Get available dates from summaries (sorted newest first)
114→function getAvailableDates(summaries: ChatSummary[]): string[] {
115→  const dateSet = new Set<string>();
116→
117→  for (const summary of summaries) {
118→    if (summary.createdAt) {
119→      dateSet.add(toDateKey(summary.createdAt));
120→    }
121→  }
122→
123→  return Array.from(dateSet).sort((a, b) => b.localeCompare(a));
124→}
125→
126→// Get total message count for a date
127→function getMessageCountForDate(
128→  summariesByDate: Map<string, ChatSummary[]>,
129→  date: string
130→): number {
131→  const summaries = summariesByDate.get(date) || [];
132→  return summaries.reduce((sum, s) => sum + (s.messageCount || 0), 0);
133→}
134→
135→// Get all topics for a date
136→function getTopicsForDate(
137→  summariesByDate: Map<string, ChatSummary[]>,
138→  date: string
139→): ChatSummary["topics"] {
140→  const summaries = summariesByDate.get(date) || [];
141→  return summaries.flatMap((s) => s.topics);
142→}
