144→export type SummaryFeedProps = {
145→  /** Initial chat/summary ID to display */
146→  initialChatId?: string;
147→  /** All summaries for the group (pre-fetched) */
148→  summaries?: ChatSummary[];
149→  /** Group title (optional, derived from summaries if not provided) */
150→  groupTitle?: string;
151→};
152→
153→export default function SummaryFeed({
154→  initialChatId,
155→  summaries: initialSummaries,
156→  groupTitle: initialGroupTitle,
157→}: SummaryFeedProps) {
158→  const router = useRouter();
159→  const safeAreaInsetTop = useSignal(
