212→  }, [summaries]);
213→
214→  const summariesByDate = useMemo(
215→    () => groupSummariesByDate(summaries),
216→    [summaries]
217→  );
218→
219→  const availableDates = useMemo(
220→    () => getAvailableDates(summaries),
221→    [summaries]
222→  );
223→
224→  const [selectedDate, setSelectedDate] = useState<string>(() => {
225→    return availableDates[0] || toDateKey(new Date().toISOString());
226→  });
227→
228→  // Only reset selectedDate when the data itself changes (not on every selectedDate change)
229→  useEffect(() => {
230→    if (availableDates.length > 0) {
231→      setSelectedDate(prev => {
232→        const todayKey = toDateKey(new Date().toISOString());
233→        // Keep current selection if it has data or is today
234→        if (availableDates.includes(prev) || prev === todayKey) return prev;
235→        // Otherwise default to most recent
236→        return availableDates[0];
237→      });
238→    }
239→  }, [availableDates]);
240→
241→  const messageCount = useMemo(
242→    () => getMessageCountForDate(summariesByDate, selectedDate),
243→    [summariesByDate, selectedDate]
244→  );
245→
246→  const topics = useMemo(
247→    () => getTopicsForDate(summariesByDate, selectedDate),
248→    [summariesByDate, selectedDate]
249→  );
250→
251→  const { prevTopics, nextTopics } = useMemo(() => {
252→    const currentIndex = availableDates.indexOf(selectedDate);
253→    const prevDate = currentIndex < availableDates.length - 1 ? availableDates[currentIndex + 1] : null;
254→    const nextDate = currentIndex > 0 ? availableDates[currentIndex - 1] : null;
255→    return {
256→      prevTopics: prevDate ? getTopicsForDate(summariesByDate, prevDate) : [],
257→      nextTopics: nextDate ? getTopicsForDate(summariesByDate, nextDate) : [],
258→    };
259→  }, [availableDates, selectedDate, summariesByDate]);
260→
261→  // Setup Telegram back button and disable vertical swipe to close
