291→      if (backButton.hide.isAvailable()) {
292→        backButton.hide();
293→      }
294→      if (backButton.offClick.isAvailable()) {
295→        backButton.offClick(handleBack);
296→      }
297→      try {
298→        backButton.unmount();
299→      } catch {
300→        // Unmount may not be available in all contexts
301→      }
302→    };
303→  }, [router]);
304→
305→  // Header hide/show on content scroll
306→  const [isHeaderHidden, setIsHeaderHidden] = useState(false);
307→  const lastContentScrollTopRef = useRef(0);
308→  const headerInnerRef = useRef<HTMLDivElement>(null);
309→  const [headerHeight, setHeaderHeight] = useState(0);
310→
311→  // Measure header height
312→  useEffect(() => {
313→    const el = headerInnerRef.current;
314→    if (!el) return;
315→    const observer = new ResizeObserver((entries) => {
316→      setHeaderHeight(entries[0].contentRect.height);
317→    });
318→    observer.observe(el);
319→    return () => observer.disconnect();
320→  }, []);
321→
322→  const handleContentScroll = useCallback(() => {
323→    const container = scrollContainerRef.current;
324→    if (!container) return;
325→
326→    const currentScrollTop = container.scrollTop;
327→    const maxScroll = container.scrollHeight - container.clientHeight;
328→
329→    // Ignore WebKit rubber-band overscroll (negative or beyond max)
330→    if (currentScrollTop < 0 || currentScrollTop > maxScroll) {
331→      return;
332→    }
333→
334→    const delta = currentScrollTop - lastContentScrollTopRef.current;
335→
336→    // Only trigger after meaningful scroll (avoid micro-jitter)
337→    if (Math.abs(delta) < 4) return;
338→
339→    if (delta > 0 && currentScrollTop > 20) {
340→      // Scrolling down — hide timeline
341→      setIsHeaderHidden(true);
342→    } else if (delta < -2 && currentScrollTop < maxScroll) {
343→      // Scrolling up (but not during bottom bounce) — show timeline
344→      setIsHeaderHidden(false);
345→    }
346→
347→    lastContentScrollTopRef.current = currentScrollTop;
348→  }, []);
349→
350→  // Slide animation state
351→  const [slideDirection, setSlideDirection] = useState<"left" | "right" | null>(
352→    null
353→  );
354→  const [isSliding, setIsSliding] = useState(false);
355→  const [oldTopics, setOldTopics] = useState<typeof topics>([]);
356→  const prevDateRef = useRef(selectedDate);
357→
358→  // Swipe detection for content area
359→  const touchStartRef = useRef<{ x: number; y: number } | null>(null);
360→  const isSwipingRef = useRef(false);
361→  const [swipeX, setSwipeX] = useState(0);
362→
363→  // Navigate to adjacent date with data
364→  const navigateToAdjacentDate = useCallback(
365→    (direction: "prev" | "next") => {
366→      const currentIndex = availableDates.indexOf(selectedDate);
367→      if (currentIndex === -1) return;
368→
369→      let targetDate: string | null = null;
370→      if (direction === "prev" && currentIndex < availableDates.length - 1) {
371→        targetDate = availableDates[currentIndex + 1];
372→      } else if (direction === "next" && currentIndex > 0) {
373→        targetDate = availableDates[currentIndex - 1];
374→      }
375→
376→      if (targetDate) {
377→        if (hapticFeedback.impactOccurred.isAvailable()) {
378→          hapticFeedback.impactOccurred("light");
379→        }
380→        const slideDir = direction === "next" ? "left" : "right";
381→        setOldTopics(topics);
382→        setSlideDirection(slideDir);
383→        setIsSliding(true);
384→        setSelectedDate(targetDate);
385→        prevDateRef.current = targetDate;
386→
387→        if (scrollContainerRef.current) {
388→          scrollContainerRef.current.scrollTop = 0;
389→        }
390→
391→        setTimeout(() => {
392→          setIsSliding(false);
393→          setSlideDirection(null);
394→        }, 180);
395→      }
396→    },
397→    [availableDates, selectedDate, topics]
398→  );
399→
400→  const SWIPE_THRESHOLD = 50;
401→
402→  const handleTouchStart = useCallback((e: React.TouchEvent) => {
403→    touchStartRef.current = {
404→      x: e.touches[0].clientX,
405→      y: e.touches[0].clientY,
406→    };
407→    isSwipingRef.current = false;
408→  }, []);
409→
410→  const handleTouchMove = useCallback((e: React.TouchEvent) => {
411→    if (!touchStartRef.current) return;
412→
413→    const deltaX = e.touches[0].clientX - touchStartRef.current.x;
414→    const deltaY = e.touches[0].clientY - touchStartRef.current.y;
415→
416→    if (!isSwipingRef.current && Math.abs(deltaX) > 10 && Math.abs(deltaX) > Math.abs(deltaY) * 1.5) {
417→      isSwipingRef.current = true;
418→    }
419→
420→    if (isSwipingRef.current) {
421→      const currentIndex = availableDates.indexOf(selectedDate);
422→      const canGoNext = currentIndex > 0;
423→      const canGoPrev = currentIndex < availableDates.length - 1;
424→
425→      let adjustedDelta = deltaX;
426→      if ((deltaX < 0 && !canGoNext) || (deltaX > 0 && !canGoPrev)) {
427→        adjustedDelta = deltaX * 0.15;
428→      } else {
429→        adjustedDelta = deltaX * 0.35;
430→      }
431→
432→      setSwipeX(adjustedDelta);
433→
434→      if (Math.abs(deltaX) >= SWIPE_THRESHOLD && Math.abs(deltaX - (deltaX > 0 ? 5 : -5)) < SWIPE_THRESHOLD) {
435→        if (hapticFeedback.selectionChanged.isAvailable()) {
436→          hapticFeedback.selectionChanged();
437→        }
438→      }
439→    }
440→  }, [availableDates, selectedDate]);
441→
442→  const handleTouchEnd = useCallback(
443→    (e: React.TouchEvent) => {
444→      if (!touchStartRef.current) return;
445→
446→      const deltaX = e.changedTouches[0].clientX - touchStartRef.current.x;
447→      const deltaY = e.changedTouches[0].clientY - touchStartRef.current.y;
448→
449→      if (Math.abs(deltaX) > SWIPE_THRESHOLD && Math.abs(deltaX) > Math.abs(deltaY) * 1.5) {
450→        if (deltaX < 0) {
451→          navigateToAdjacentDate("next");
452→        } else {
453→          navigateToAdjacentDate("prev");
454→        }
455→      }
456→
457→      setSwipeX(0);
458→      touchStartRef.current = null;
459→      isSwipingRef.current = false;
460→    },
461→    [navigateToAdjacentDate]
462→  );
463→
464→  // Handle date selection with slide animation
465→  const handleDateSelect = useCallback(
466→    (date: string) => {
467→      if (date === selectedDate) return;
468→
469→      setIsHeaderHidden(false);
470→      setOldTopics(topics);
471→
472→      const direction = date > prevDateRef.current ? "left" : "right";
473→      setSlideDirection(direction);
474→      setIsSliding(true);
475→
476→      setSelectedDate(date);
477→      prevDateRef.current = date;
478→
479→      if (scrollContainerRef.current) {
480→        scrollContainerRef.current.scrollTop = 0;
481→      }
482→
483→      setTimeout(() => {
484→        setIsSliding(false);
485→        setSlideDirection(null);
486→      }, 180);
487→    },
488→    [selectedDate, topics]
489→  );
490→
491→  // Handle "Today" button - always navigate to today
492→  const handleTodayClick = useCallback(() => {
493→    if (hapticFeedback.impactOccurred.isAvailable()) {
