507→    });
508→  }, []);
509→
510→  if (isLoading) {
511→    return (
512→      <div
513→        className="fixed inset-0 flex items-center justify-center"
514→        style={{ background: "#fff" }}
515→      >
516→        <div className="w-6 h-6 border-2 border-black/10 border-t-black/40 rounded-full animate-spin" />
517→      </div>
518→    );
519→  }
520→
521→  if (error) {
