523→      <div
524→        className="fixed inset-0 flex flex-col items-center justify-center gap-4"
525→        style={{ background: "#fff" }}
526→      >
527→        <p className="text-black/50">{error}</p>
528→        <button
529→          onClick={() => window.location.reload()}
530→          className="px-4 py-2 bg-black/5 rounded-lg text-black text-sm"
531→        >
532→          Retry
533→        </button>
534→      </div>
535→    );
536→  }
537→
538→  if (summaries.length === 0) {
539→    return (
540→      <div
541→        className="fixed inset-0 flex items-center justify-center"
542→        style={{ background: "#fff" }}
543→      >
544→        <p className="text-black/50">No summaries available</p>
