669→          {/* Next day's content - peeking from right */}
670→          {nextTopics.length > 0 && !isSliding && (
671→            <div
672→              className="absolute top-0 bottom-0 px-4 pt-2 pb-8 overflow-hidden pointer-events-none"
673→              style={{
