745→              <EmptyState />
746→            )}
747→
748→            {/* Bottom safe area padding */}
749→            <div className="h-20 shrink-0" />
750→          </div>
751→        </div>
752→
753→        {/* CSS Keyframes for slide animations */}
754→        <style jsx>{`
