 6→
 7→type CommunityPhotoSettings = {
 8→  photoBase64?: string;
 9→  photoMimeType?: string;
10→};
11→
12→export async function GET(req: Request): Promise<NextResponse> {
13→  try {
14→    const { searchParams } = new URL(req.url);
15→    const chatId = searchParams.get("chatId");
16→    const db = getDatabase();
17→
18→    const result = chatId
19→      ? await fetchSummariesByChatId(db, chatId)
20→      : (
21→          await db
22→            .select({
23→              summary: summaries,
24→              community: communities,
25→            })
26→            .from(summaries)
27→            .innerJoin(communities, eq(summaries.communityId, communities.id))
28→            .where(eq(communities.isPublic, true))
29→            .orderBy(desc(summaries.createdAt))
30→        ).map(({ summary, community }) => ({ ...summary, community }));
31→
32→    const transformedSummaries = result.map((item) => {
33→      const settings = item.community.settings as CommunityPhotoSettings | null;
34→      return {
35→        id: item.id,
36→        chatId: String(item.community.chatId),
37→        title: item.chatTitle,
38→        messageCount: item.messageCount,
39→        oneliner: item.oneliner,
40→        photoBase64: settings?.photoBase64,
41→        photoMimeType: settings?.photoMimeType,
42→        topics: item.topics.map((topic, index) => ({
43→          id: `${item.id}-${index}`,
44→          title: topic.title,
45→          content: topic.content,
46→          sources: topic.sources,
47→        })),
48→        createdAt: item.createdAt.toISOString(),
49→      };
50→    });
51→
52→    return NextResponse.json({ summaries: transformedSummaries });
53→  } catch (error) {
54→    console.error("[api/summaries] Failed to fetch summaries:", error);
55→    return NextResponse.json(
56→      { error: "Failed to fetch summaries" },
57→      { status: 500 }
58→    );
59→  }
60→}
61→
62→type SummaryWithCommunity = Summary & {
63→  community: { chatId: bigint; settings: unknown };
64→};
65→
66→async function fetchSummariesByChatId(
67→  db: ReturnType<typeof getDatabase>,
68→  chatId: string
69→): Promise<SummaryWithCommunity[]> {
70→  const community = await db.query.communities.findFirst({
71→    where: and(
72→      eq(communities.chatId, BigInt(chatId)),
73→      eq(communities.isPublic, true)
74→    ),
75→  });
76→
77→  if (!community) return [];
78→
79→  const summaryResults = await db.query.summaries.findMany({
80→    where: eq(summaries.communityId, community.id),
81→    orderBy: [desc(summaries.createdAt)],
82→  });
83→
84→  return summaryResults.map((s) => ({ ...s, community }));
85→}
