 14→import {
 15→  getCloudValue,
 16→  setCloudValue,
 17→} from "@/lib/telegram/mini-app/cloud-storage";
 18→
 19→import type { ChatSummary } from "./SummaryFeed";
 20→
 21→const SESSION_STORAGE_KEY = "summaries_cache";
 22→const CLOUD_STORAGE_KEY = "summaries_cache";
 23→const CLOUD_MAX_SIZE = 3500; // Leave margin under 4096 limit
 24→
 25→type SummariesContextType = {
 26→  summaries: ChatSummary[];
 27→  setSummaries: (summaries: ChatSummary[]) => void;
 28→  hasCachedData: boolean;
 29→};
 30→
 31→const SummariesContext = createContext<SummariesContextType>({
 32→  summaries: [],
 33→  setSummaries: () => {},
 34→  hasCachedData: false,
 35→});
 36→
 37→// Strip photos from summaries to fit in cloud storage (4KB limit)
 38→function stripPhotos(summaries: ChatSummary[]): Omit<ChatSummary, "photoBase64" | "photoMimeType">[] {
 39→  return summaries.map((summary) => {
 40→    const copy = { ...summary };
 41→    delete copy.photoBase64;
 42→    delete copy.photoMimeType;
 43→    return copy;
 44→  });
 45→}
 46→
 47→// Trim summaries to fit within size limit
 48→function trimToFit(summaries: ChatSummary[], maxSize: number): ChatSummary[] {
 49→  // Start with all summaries, remove oldest until it fits
 50→  let trimmed = [...summaries];
 51→  let json = JSON.stringify(trimmed);
 52→
 53→  while (json.length > maxSize && trimmed.length > 0) {
 54→    trimmed = trimmed.slice(0, -1); // Remove last (oldest) summary
 55→    json = JSON.stringify(trimmed);
 56→  }
 57→
 58→  return trimmed;
 59→}
 60→
 61→function loadFromSession(): ChatSummary[] {
 62→  if (typeof window === "undefined") return [];
 63→  try {
 64→    const cached = sessionStorage.getItem(SESSION_STORAGE_KEY);
 65→    return cached ? JSON.parse(cached) : [];
 66→  } catch {
 67→    return [];
 68→  }
 69→}
 70→
 71→async function loadFromCloud(): Promise<ChatSummary[]> {
 72→  try {
 73→    const cached = await getCloudValue(CLOUD_STORAGE_KEY);
 74→    if (cached && typeof cached === "string") {
 75→      return JSON.parse(cached);
 76→    }
 77→  } catch (error) {
 78→    console.error("Failed to load summaries from cloud storage:", error);
 79→  }
 80→  return [];
 81→}
 82→
 83→async function saveToCloud(summaries: ChatSummary[]): Promise<void> {
 84→  try {
 85→    // Strip photos and trim to fit
 86→    const stripped = stripPhotos(summaries);
 87→    const trimmed = trimToFit(stripped, CLOUD_MAX_SIZE);
 88→    await setCloudValue(CLOUD_STORAGE_KEY, JSON.stringify(trimmed));
 89→  } catch (error) {
 90→    console.error("Failed to save summaries to cloud storage:", error);
 91→  }
 92→}
 93→
 94→export function SummariesProvider({ children }: { children: ReactNode }) {
 95→  const [summaries, setSummariesState] = useState<ChatSummary[]>([]);
 96→  const [hasCachedData, setHasCachedData] = useState(false);
 97→  const cloudLoadedRef = useRef(false);
 98→
 99→  // Load from session storage first (instant), then cloud storage (async)
100→  useEffect(() => {
101→    // 1. Session storage - instant
102→    const sessionCached = loadFromSession();
103→    if (sessionCached.length > 0) {
104→      setSummariesState(sessionCached);
105→      setHasCachedData(true);
106→    }
107→
108→    // 2. Cloud storage - async, provides cross-device sync
109→    if (!cloudLoadedRef.current) {
110→      cloudLoadedRef.current = true;
111→      loadFromCloud().then((cloudCached) => {
112→        if (cloudCached.length > 0) {
113→          // Only use cloud data if we don't have session data
114→          // (session data is more complete with photos)
115→          setSummariesState((current) => {
116→            if (current.length === 0) {
117→              setHasCachedData(true);
118→              return cloudCached;
119→            }
120→            return current;
121→          });
122→        }
123→      });
124→    }
125→  }, []);
126→
127→  const setSummaries = useCallback((newSummaries: ChatSummary[]) => {
128→    setSummariesState(newSummaries);
129→    setHasCachedData(newSummaries.length > 0);
130→
131→    // Save to session storage (full data with photos)
132→    try {
133→      sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(newSummaries));
134→    } catch {
135→      // Storage full or unavailable
136→    }
137→
138→    // Save to cloud storage (without photos, for cross-device sync)
139→    saveToCloud(newSummaries);
140→  }, []);
141→
142→  const value = useMemo(
143→    () => ({ summaries, setSummaries, hasCachedData }),
144→    [summaries, setSummaries, hasCachedData]
145→  );
146→
147→  return (
148→    <SummariesContext.Provider value={value}>
149→      {children}
150→    </SummariesContext.Provider>
151→  );
152→}
153→
154→export function useSummaries(): SummariesContextType {
155→  return useContext(SummariesContext);
156→}
