187→  const groups: { date: string; messages: Message[] }[] = [];
188→  let currentDate = "";
189→
190→  for (const message of messages) {
191→    if (message.date !== currentDate) {
192→      currentDate = message.date;
193→      groups.push({ date: currentDate, messages: [message] });
194→    } else {
195→      groups[groups.length - 1].messages.push(message);
196→    }
197→  }
198→
199→  return groups;
200→}
