253→// Swipe threshold to trigger action (in pixels)
254→const SWIPE_THRESHOLD = 100;
255→// Max rotation angle in degrees
256→const MAX_ROTATION = 8;
257→// Back card rotation
258→const BACK_CARD_ROTATION = -2;
259→// Smooth ease-out for animations
260→const EASE_OUT = "cubic-bezier(0.0, 0.0, 0.2, 1)";
