289→
290→  // Swipe state
291→  const [swipeX, setSwipeX] = useState(0);
292→  const [isDragging, setIsDragging] = useState(false);
293→  const [isAnimatingOut, setIsAnimatingOut] = useState(false);
294→  const [isBackCardTransitioning, setIsBackCardTransitioning] = useState(false);
295→  const touchStartRef = useRef<{ x: number; y: number } | null>(null);
296→  const isHorizontalSwipeRef = useRef<boolean | null>(null);
297→
298→  // Track card index for animation key
299→  const [cardKey, setCardKey] = useState(0);
300→  const [isResetting, setIsResetting] = useState(false);
301→  const [activeSwipeDirection, setActiveSwipeDirection] = useState<
302→    "left" | "right" | null
303→  >(null);
304→
305→  // Page entrance animation
306→  const [isPageMounted, setIsPageMounted] = useState(false);
307→
308→  const currentChat = summaries[currentIndex];
309→  const nextChat = summaries[currentIndex + 1];
310→  const remainingCount = summaries.length - currentIndex;
311→
312→  // Reset scroll position when chat changes
313→  useEffect(() => {
314→    if (scrollContainerRef.current) {
315→      scrollContainerRef.current.scrollTop = 0;
316→    }
317→  }, [currentIndex]);
318→
319→  // Trigger entrance animation after mount
320→  useEffect(() => {
321→    requestAnimationFrame(() => {
322→      requestAnimationFrame(() => {
323→        setIsPageMounted(true);
324→      });
325→    });
326→  }, []);
327→
328→  // Setup Telegram back button and disable vertical swipe
329→  useEffect(() => {
330→    // Disable vertical swipe to close the app
331→    if (swipeBehavior.disableVertical.isAvailable()) {
332→      swipeBehavior.disableVertical();
333→    }
334→
335→    // Mount and show back button
336→    try {
337→      backButton.mount();
338→    } catch {
339→      // Mount may not be available in all contexts
340→    }
341→    if (backButton.show.isAvailable()) {
342→      backButton.show();
343→    }
344→
345→    const handleBack = () => {
346→      if (hapticFeedback.impactOccurred.isAvailable()) {
