354→    }
355→
356→    return () => {
357→      // Re-enable vertical swipe when leaving
358→      if (swipeBehavior.enableVertical.isAvailable()) {
359→        swipeBehavior.enableVertical();
360→      }
361→      // Hide and unmount back button
362→      if (backButton.hide.isAvailable()) {
363→        backButton.hide();
364→      }
365→      if (backButton.offClick.isAvailable()) {
