499→            setCardKey((k) => k + 1);
500→            setSwipeX(0);
501→            setIsAnimatingOut(false);
502→            setIsBackCardTransitioning(false);
503→            setIsDragging(false);
504→            setActiveSwipeDirection(null);
505→
506→            requestAnimationFrame(() => {
507→              setIsResetting(false);
508→            });
509→          });
510→        }, 300);
511→      }, 300);
512→    },
513→    [currentIndex, router, summaries.length]
514→  );
515→
516→  const handleTouchEnd = useCallback(() => {
517→    if (!isDragging || isAnimatingOut) return;
518→
519→    const shouldTriggerAction = Math.abs(swipeX) >= SWIPE_THRESHOLD;
520→
521→    if (shouldTriggerAction) {
522→      const direction = swipeX > 0 ? "right" : "left";
523→      completeSwipe(direction);
524→    } else {
525→      // Snap back
526→      setSwipeX(0);
527→      setIsDragging(false);
528→    }
529→
530→    touchStartRef.current = null;
531→    isHorizontalSwipeRef.current = null;
532→  }, [isDragging, isAnimatingOut, swipeX, completeSwipe]);
533→
534→  if (!currentChat) {
535→    return (
536→      <div
537→        className="fixed inset-0 flex items-center justify-center"
538→        style={{ background: "#ffffff" }}
539→      >
540→        <p className="text-black/60">No chats available</p>
541→      </div>
