  61→// Basic Solana address validation (base58, 32-44 chars)
  62→export const isValidSolanaAddress = (address: string): boolean => {
  63→  const base58Regex = /^[1-9A-HJ-NP-Za-km-z]{32,44}$/;
  64→  return base58Regex.test(address);
