 102→      ...filtered,
 103→    ].slice(0, MAX_RECENT_RECIPIENTS);
 104→
 105→    await setCloudValue(RECENT_RECIPIENTS_KEY, JSON.stringify(updated));
 106→  } catch {}
 107→};
