 109→// Truncate (floor) to specific decimal places - never rounds up
 110→const truncateDecimals = (num: number, decimals: number): string => {
 111→  const factor = Math.pow(10, decimals);
 112→  const truncated = Math.floor(num * factor) / factor;
 113→  return truncated.toFixed(decimals);
