 175→export default function SendSheet({
 176→  open,
 177→  onOpenChange,
 178→  initialRecipient,
 179→  onValidationChange,
 180→  onFormValuesChange,
 181→  step,
 182→  onStepChange,
 183→  balance,
 184→  walletAddress,
 185→  solPriceUsd: solPriceUsdProp,
 186→  isSolPriceLoading: isSolPriceLoadingProp,
 187→  sentAmountSol,
 188→  sendError,
 189→  isSending = false,
 190→  tokenHoldings = [],
 191→}: SendSheetProps) {
 192→  const { bottom: safeBottom } = useTelegramSafeArea();
 193→  const [mounted, setMounted] = useState(false);
 194→  const [headerHeight, setHeaderHeight] = useState(0);
 195→  const [rendered, setRendered] = useState(false);
 196→  const [show, setShow] = useState(false);
 197→  const sheetRef = useRef<HTMLDivElement>(null);
 198→  const overlayRef = useRef<HTMLDivElement>(null);
 199→  const dragStartY = useRef(0);
 200→  const dragDelta = useRef(0);
 201→  const isDragging = useRef(false);
 202→  const isClosing = useRef(false);
 203→
 204→  // Detect iOS for platform-specific focus handling
 205→  const [isIOS] = useState(() => {
 206→    try {
 207→      const params = retrieveLaunchParams();
 208→      return params.tgWebAppPlatform === "ios";
 209→    } catch {
 210→      return false;
 211→    }
 212→  });
 213→
 214→  // Abbreviate wallet address for display
 215→  const abbreviatedAddress = walletAddress
 216→    ? `${walletAddress.slice(0, 4)}…${walletAddress.slice(-4)}`
 217→    : '';
 218→
 219→  // Token selection state
 220→  const [tokenSearchQuery, setTokenSearchQuery] = useState("");
 221→  const [selectedToken, setSelectedToken] = useState<TokenHolding | null>(null);
 222→
 223→  const filteredTokens = useMemo(() => {
 224→    if (!tokenSearchQuery.trim()) return tokenHoldings;
 225→    const q = tokenSearchQuery.toLowerCase();
 226→    return tokenHoldings.filter(
 227→      (t) =>
 228→        t.symbol.toLowerCase().includes(q) ||
 229→        t.name.toLowerCase().includes(q),
 230→    );
 231→  }, [tokenHoldings, tokenSearchQuery]);
 232→
 233→  // Form state
 234→  const [amountStr, setAmountStr] = useState("");
 235→  const [recipient, setRecipient] = useState("");
 236→  const [currency, setCurrency] = useState<'SOL' | 'USD'>('SOL');
 237→  const [lastAmount, setLastAmount] = useState<LastAmount | null>(null);
 238→  const [recentRecipients, setRecentRecipients] = useState<RecentRecipient[]>([]);
 239→  const [solPriceUsdState, setSolPriceUsdState] = useState<number | null>(null);
 240→  const [isSolPriceLoadingState, setIsSolPriceLoadingState] = useState(true);
 241→  const inputRef = useRef<HTMLInputElement>(null);
 242→  const amountInputRef = useRef<HTMLInputElement>(null);
 243→  const amountTextRef = useRef<HTMLParagraphElement>(null);
 244→  const [caretLeft, setCaretLeft] = useState(0);
 245→
 246→  // Convert balance from lamports to SOL
 247→  const balanceInSol = balance ? balance / LAMPORTS_PER_SOL : 0;
 248→  const isUsingExternalPrice =
 249→    solPriceUsdProp !== undefined || isSolPriceLoadingProp !== undefined;
 250→  const solPriceUsd = isUsingExternalPrice
 251→    ? solPriceUsdProp ?? null
 252→    : solPriceUsdState;
 253→  const isSolPriceLoading = isUsingExternalPrice
 254→    ? isSolPriceLoadingProp ?? solPriceUsd === null
 255→    : isSolPriceLoadingState;
 256→  const balanceInUsd = solPriceUsd ? balanceInSol * solPriceUsd : null;
 257→  const solanaFeeUsd = solPriceUsd ? SOLANA_FEE_SOL * solPriceUsd : null;
 258→
 259→  useEffect(() => {
 260→    setMounted(true);
 261→  }, []);
 262→
 263→  // Open: mount elements, force layout, then trigger CSS transition
 264→  useEffect(() => {
 265→    if (open) {
 266→      isClosing.current = false;
 267→      setRendered(true);
 268→    }
 269→  }, [open]);
 270→
 271→  useEffect(() => {
 272→    if (rendered && open && !show && !isClosing.current) {
 273→      sheetRef.current?.getBoundingClientRect();
 274→      setShow(true);
 275→    }
 276→  }, [rendered, open, show]);
 277→
 278→  // Measure header
 279→  useEffect(() => {
 280→    if (!open) return;
 281→    const header = document.querySelector("header");
 282→    if (header) {
 283→      setHeaderHeight(header.getBoundingClientRect().bottom);
 284→    }
 285→  }, [open]);
 286→
 287→  // Load SOL price for USD conversions when not provided externally
 288→  useEffect(() => {
 289→    if (isUsingExternalPrice) {
 290→      setIsSolPriceLoadingState(false);
 291→      return;
 292→    }
 293→
 294→    let isMounted = true;
 295→
 296→    const loadPrice = async () => {
 297→      try {
 298→        const price = await fetchSolUsdPrice();
 299→        if (!isMounted) return;
 300→        setSolPriceUsdState(price);
 301→      } catch (error) {
 302→        console.error("Failed to fetch SOL price", error);
 303→        if (!isMounted) return;
 304→        setSolPriceUsdState(SOL_PRICE_USD);
 305→      } finally {
 306→        if (isMounted) {
 307→          setIsSolPriceLoadingState(false);
 308→        }
 309→      }
 310→    };
 311→
 312→    void loadPrice();
 313→
 314→    return () => {
 315→      isMounted = false;
 316→    };
 317→  }, [isUsingExternalPrice]);
 318→
 319→  // Reset state when opening
 320→  useEffect(() => {
 321→    if (open) {
 322→      setAmountStr("");
 323→      setRecipient(initialRecipient || "");
 324→      setCurrency('SOL');
 325→      setTokenSearchQuery("");
 326→      setSelectedToken(null);
 327→      void getLastAmount().then(setLastAmount);
 328→      void getRecentRecipients().then(setRecentRecipients);
 329→    }
 330→  }, [open, initialRecipient]);
 331→
 332→  // Auto-focus and blur based on step
 333→  useEffect(() => {
 334→    if (!open) return;
 335→
 336→    if (!isIOS) {
 337→      if (step === 2) {
 338→        const timer = setTimeout(() => {
 339→          inputRef.current?.focus();
 340→        }, 300);
 341→        return () => clearTimeout(timer);
 342→      }
 343→      if (step === 3) {
 344→        const timer = setTimeout(() => {
 345→          amountInputRef.current?.focus({ preventScroll: true });
 346→        }, 300);
 347→        return () => clearTimeout(timer);
 348→      }
 349→    }
 350→
 351→    if (step === 4 || step === 5) {
 352→      amountInputRef.current?.blur();
 353→      inputRef.current?.blur();
 354→    }
 355→  }, [open, step, isIOS]);
 356→
 357→  // Update caret position based on actual text width
 358→  useEffect(() => {
 359→    if (amountTextRef.current) {
 360→      setCaretLeft(amountTextRef.current.offsetWidth);
 361→    } else {
 362→      setCaretLeft(0);
 363→    }
 364→  }, [amountStr]);
 365→
 366→  // Prevent backspace from navigating when on step 3
 367→  const amountStrRef = useRef(amountStr);
 368→  useEffect(() => {
 369→    amountStrRef.current = amountStr;
 370→  }, [amountStr]);
 371→
 372→  useEffect(() => {
 373→    if (!open || step !== 3) return;
 374→
 375→    const handleKeyDown = (e: KeyboardEvent) => {
 376→      if (e.key === 'Backspace') {
 377→        if (!amountStrRef.current) {
 378→          e.preventDefault();
 379→          e.stopPropagation();
 380→        }
 381→      }
 382→    };
 383→
 384→    window.addEventListener('keydown', handleKeyDown, true);
 385→    return () => window.removeEventListener('keydown', handleKeyDown, true);
 386→  }, [open, step]);
 387→
 388→  // Save last amount when moving to step 4 (confirmation)
 389→  useEffect(() => {
 390→    if (step === 4 && amountStr) {
 391→      const amount = parseFloat(amountStr);
 392→      if (!isNaN(amount) && amount > 0) {
 393→        const solAmount =
 394→          currency === 'USD'
 395→            ? solPriceUsd
 396→              ? amount / solPriceUsd
 397→              : NaN
 398→            : amount;
 399→        if (!isNaN(solAmount) && solAmount > 0) {
 400→          void saveLastAmount(solAmount, solPriceUsd);
 401→        }
 402→      }
 403→    }
 404→  }, [step, amountStr, currency, solPriceUsd]);
 405→
 406→  // Handle value reporting to parent
 407→  useEffect(() => {
 408→    if (onFormValuesChange) {
 409→      let finalAmount = amountStr;
 410→      if (currency === 'USD' && amountStr) {
 411→        const usdVal = parseFloat(amountStr);
 412→        if (!isNaN(usdVal)) {
 413→          finalAmount = solPriceUsd
 414→            ? (usdVal / solPriceUsd).toFixed(6)
 415→            : "";
 416→        }
 417→      }
 418→      onFormValuesChange({ amount: finalAmount, recipient });
 419→    }
 420→  }, [amountStr, recipient, currency, onFormValuesChange, solPriceUsd]);
 421→
 422→  // Validation Logic
 423→  useEffect(() => {
 424→    if (!open) {
 425→      onValidationChange?.(false);
 426→      return;
 427→    }
 428→
 429→    const recipientTrimmed = recipient.trim();
 430→    const isRecipientValid = isValidSolanaAddress(recipientTrimmed) || isValidTelegramUsername(recipientTrimmed);
 431→
 432→    if (step === 1) {
 433→      // Token selection step — always valid (user picks from list)
 434→      onValidationChange?.(true);
 435→      return;
 436→    }
 437→
 438→    if (step === 2) {
 439→      onValidationChange?.(isRecipientValid);
 440→      return;
 441→    }
 442→
 443→    const amount = parseFloat(amountStr);
 444→    const isAmountValid = !isNaN(amount) && amount > 0 && isFinite(amount);
 445→
 446→    const amountInSol =
 447→      currency === 'SOL'
 448→        ? amount
 449→        : solPriceUsd
 450→          ? amount / solPriceUsd
 451→          : NaN;
 452→    const hasEnoughBalance =
 453→      !isNaN(amountInSol) && amountInSol <= balanceInSol;
 454→
 455→    if (step === 3) {
 456→      const isValid =
 457→        isAmountValid &&
 458→        isRecipientValid &&
 459→        hasEnoughBalance &&
 460→        (currency === 'SOL' || !!solPriceUsd);
 461→      onValidationChange?.(isValid);
 462→      return;
 463→    }
 464→
 465→    if (step === 4) {
 466→      const hasEnoughSolForFee = balanceInSol >= amountInSol + SOLANA_FEE_SOL;
 467→
 468→      const isValid =
 469→        isAmountValid &&
 470→        isRecipientValid &&
 471→        hasEnoughBalance &&
 472→        hasEnoughSolForFee &&
 473→        (currency === 'SOL' || !!solPriceUsd);
 474→      onValidationChange?.(isValid);
 475→      return;
 476→    }
 477→
 478→    onValidationChange?.(false);
 479→  }, [step, amountStr, recipient, open, onValidationChange, currency, balanceInSol, solPriceUsd]);
 480→
 481→
 482→  const handleRecipientSelect = (selected: string) => {
 483→    if (hapticFeedback.impactOccurred.isAvailable()) {
 484→      hapticFeedback.impactOccurred("light");
 485→    }
 486→    setRecipient(selected);
 487→    onStepChange(3);
 488→    if (isIOS) {
 489→      amountInputRef.current?.focus({ preventScroll: true });
 490→    }
 491→  };
 492→
 493→  const handlePresetAmount = (val: number | string) => {
 494→    if (hapticFeedback.impactOccurred.isAvailable()) {
 495→      hapticFeedback.impactOccurred("light");
 496→    }
 497→    if (document.activeElement !== amountInputRef.current) {
 498→      amountInputRef.current?.focus({ preventScroll: true });
 499→    }
 500→    const strVal = typeof val === 'string' ? val : val.toString();
 501→    setAmountStr(strVal);
 502→  };
 503→
 504→  const handleTokenSelect = (token: TokenHolding) => {
 505→    if (hapticFeedback.impactOccurred.isAvailable()) {
 506→      hapticFeedback.impactOccurred("light");
 507→    }
 508→    setSelectedToken(token);
 509→    setTokenSearchQuery("");
 510→    onStepChange(2);
 511→  };
 512→
 513→  const tokenSymbol = selectedToken?.symbol || 'SOL';
 514→
 515→  // Computed display values
 516→  const secondaryDisplay = useMemo(() => {
 517→    const val = parseFloat(amountStr);
