                </div>
                <div className="flex-1 flex flex-col gap-0.5 py-2.5">
                  <p className="text-base leading-5 text-black">Balance</p>
                  <p
                    className="text-[13px] leading-4"
                    style={{ color: "rgba(60, 60, 67, 0.6)" }}
