    } else {
      setCaretLeft(0);
    }
  }, [amountStr]);

  // Prevent backspace from navigating when on step 3
  const amountStrRef = useRef(amountStr);
  useEffect(() => {
    amountStrRef.current = amountStr;
  }, [amountStr]);

  useEffect(() => {
