 1→import { AnchorProvider, Program } from "@coral-xyz/anchor";
 2→
 3→import type { TelegramTransfer } from "../../../../../target/types/telegram_transfer";
 4→import type { TelegramDeposit } from "../../../types/deposits";
 5→import { getDepositPda, getVaultPda, numberToBN } from "../solana-helpers";
 6→import { getDeposit } from "./get-deposit";
 7→
 8→export const refundDeposit = async (
 9→  provider: AnchorProvider,
10→  transferProgram: Program<TelegramTransfer>,
11→  username: string,
12→  amount: number
13→): Promise<TelegramDeposit> => {
14→  const deposit = await getDeposit(provider, transferProgram, username);
15→  const userPublicKey = provider.wallet.publicKey;
16→  const vaultPda = getVaultPda(transferProgram);
17→  const depositPda = getDepositPda(userPublicKey, username, transferProgram);
18→
19→  if (deposit.amount < amount) {
20→    throw new Error("Insufficient deposit");
21→  }
22→  if (deposit.user.toBase58() !== userPublicKey.toBase58()) {
23→    throw new Error("This deposit does not belong to the current user");
24→  }
25→
26→  const amountBN = numberToBN(amount);
27→
28→  await transferProgram.methods
29→    .refundDeposit(amountBN)
30→    .accounts({
31→      depositor: userPublicKey,
32→      // @ts-expect-error - vaultPda is a PublicKey
33→      vault: vaultPda,
34→      deposit: depositPda,
35→    })
36→    .rpc({ commitment: "confirmed" });
37→
38→  const updatedDeposit = await getDeposit(provider, transferProgram, username);
39→  return updatedDeposit;
40→};
