 30→const normalizeBytes = (value: unknown): Uint8Array => {
 31→  if (typeof value === "string") {
 32→    return new Uint8Array(Buffer.from(value, "base64"));
 33→  }
 34→  if (Array.isArray(value)) {
 35→    return Uint8Array.from(value);
 36→  }
 37→  if (value && typeof value === "object") {
 38→    const entries = Object.entries(value)
 39→      .map(([k, v]) => [Number(k), v as number])
 40→      .sort(([a], [b]) => a - b)
 41→      .map(([, v]) => v);
 42→    return Uint8Array.from(entries);
 43→  }
 44→  throw new Error("Invalid byte array format");
 45→};
