 47→const deserializeTransaction = (
 48→  serializedTx: string
 49→): Transaction | VersionedTransaction => {
 50→  const buffer = Buffer.from(serializedTx, "base64");
 51→  try {
 52→    return VersionedTransaction.deserialize(buffer);
 53→  } catch {
 54→    return Transaction.from(buffer);
 55→  }
 56→};
