236→    const bodyJson = JSON.parse(bodyString);
237→
238→    const {
239→      storeTx,
240→      userPubKey,
241→      recipientPubKey,
242→      username,
243→      amount,
244→      processedInitDataBytes,
245→      telegramSignatureBytes,
246→      telegramPublicKeyBytes,
247→    } = bodyJson;
