249→    if (
250→      !storeTx ||
251→      !userPubKey ||
252→      !recipientPubKey ||
253→      !username ||
254→      !amount ||
255→      !processedInitDataBytes ||
256→      !telegramSignatureBytes ||
257→      !telegramPublicKeyBytes
258→    ) {
259→      return NextResponse.json(
260→        { error: "transaction and payer are required" },
261→        { status: 400 }
262→      );
263→    }
264→    if (typeof storeTx !== "string") {
265→      return NextResponse.json(
266→        { error: "Invalid transaction format" },
267→        { status: 400 }
268→      );
