279→    const telegramPublicKey = normalizeBytes(telegramPublicKeyBytes);
280→
281→    const storeResult = await storeInitData(
282→      provider,
283→      parsedStoreTx,
284→      payerWallet
285→    );
286→    if (!storeResult) {
287→      return NextResponse.json(
288→        { error: "Failed to store init data" },
289→        { status: 500 }
