 64→type CachedBalance = {
 65→  lamports: number;
 66→  fetchedAt: number;
 67→};
 68→
 69→const BALANCE_CACHE_TTL_MS = 10_000;
 70→
 71→let balanceCache: CachedBalance | null = null;
 72→let balancePromise: Promise<number> | null = null;
 73→
 74→const shouldUseCachedBalance = (forceRefresh: boolean): boolean => {
 75→  if (forceRefresh) return false;
 76→  if (!balanceCache) return false;
 77→
 78→  const age = Date.now() - balanceCache.fetchedAt;
 79→  return age < BALANCE_CACHE_TTL_MS;
 80→};
 81→
 82→const setCachedBalance = (lamports: number) => {
 83→  balanceCache = { lamports, fetchedAt: Date.now() };
 84→};
 85→
 86→export const getWalletBalance = async (
 87→  forceRefresh = false
 88→): Promise<number> => {
 89→  if (shouldUseCachedBalance(forceRefresh)) {
 90→    return balanceCache!.lamports;
 91→  }
 92→
 93→  if (!forceRefresh && balancePromise) {
 94→    return balancePromise;
 95→  }
 96→
 97→  const loader = (async () => {
 98→    const connection = getConnection();
 99→    const keypair = await getWalletKeypair();
100→
101→    const lamports = await connection.getBalance(
102→      keypair.publicKey,
103→      "confirmed"
104→    );
105→    setCachedBalance(lamports);
106→
107→    return lamports;
108→  })();
109→
110→  balancePromise = loader;
111→
112→  try {
113→    return await loader;
114→  } finally {
115→    if (balancePromise === loader) {
116→      balancePromise = null;
117→    }
118→  }
119→};
120→
121→const invalidateBalanceCache = () => {
122→  balanceCache = null;
123→  balancePromise = null;
124→};
