131→
132→  let lastLamports = balanceCache?.lamports;
133→
134→  const subscriptionId = await connection.onAccountChange(
135→    keypair.publicKey,
136→    (accountInfo) => {
137→      const lamports = accountInfo.lamports;
138→      if (typeof lastLamports === "number" && lamports === lastLamports) {
139→        return;
140→      }
141→
142→      lastLamports = lamports;
