 40→              fromMint: params.fromMint,
 41→              toMint: params.toMint,
 42→              fromAmount: params.fromAmount,
 43→              fromDecimals: params.fromDecimals,
 44→              toDecimals: params.toDecimals,
 45→              userPublicKey,
 46→            }),
 47→          }
 48→        );
 49→
 50→        if (quoteResponse.error) {
 51→          setError(quoteResponse.error);
 52→          setState("idle");
 53→          return { success: false, error: quoteResponse.error };
 54→        }
 55→
 56→        setState("signing");
 57→
 58→        const result = await executeSwapTransaction(
 59→          quoteResponse.transaction,
 60→          keypair,
 61→          quoteResponse.lastValidBlockHeight,
 62→          params.fromAmount,
 63→          params.fromSymbol,
 64→          quoteResponse.expectedOutAmount,
 65→          params.toSymbol
 66→        );
 67→
 68→        setState("idle");
 69→
 70→        if (!result.success && result.error) {
 71→          setError(result.error);
 72→        }
 73→
 74→        return result;
 75→      } catch (err) {
 76→        console.error("[useSwap] Error:", err);
 77→        const errorMessage =
 78→          err instanceof Error ? err.message : SWAP_ERRORS.TRANSACTION_FAILED;
 79→        setError(errorMessage);
 80→        setState("idle");
 81→        return { success: false, error: errorMessage };
 82→      }
 83→    },
 84→    [getKeypair]
 85→  );
 86→
 87→  const resetError = useCallback(() => {
 88→    setError(null);
 89→  }, []);
 90→
 91→  return {
 92→    executeSwap,
 93→    state,
 94→    isLoading: state !== "idle",
 95→    isQuoting: state === "quoting",
 96→    isSigning: state === "signing",
 97→    isConfirming: state === "confirming",
 98→    error,
 99→    resetError,
100→  };
101→}
