 1→import { Keypair, VersionedTransaction } from "@solana/web3.js";
 2→
 3→import { getConnection } from "../solana/rpc/connection";
 4→import { SWAP_ERRORS } from "./constants";
 5→import type { SwapResult } from "./types";
 6→
 7→export async function executeSwapTransaction(
 8→  serializedTransaction: string,
 9→  userKeypair: Keypair,
10→  lastValidBlockHeight: number,
11→  fromAmount: number,
12→  fromSymbol: string,
13→  toAmount: number,
14→  toSymbol: string
15→): Promise<SwapResult> {
16→  const connection = getConnection();
17→
18→  try {
19→    const transactionBuffer = Buffer.from(serializedTransaction, "base64");
20→    const transaction = VersionedTransaction.deserialize(transactionBuffer);
21→
22→    transaction.sign([userKeypair]);
23→
24→    const signature = await connection.sendRawTransaction(
25→      transaction.serialize(),
26→      {
27→        skipPreflight: false,
28→        maxRetries: 2,
29→      }
30→    );
31→
32→    const confirmation = await connection.confirmTransaction(
33→      {
34→        signature,
35→        blockhash: transaction.message.recentBlockhash,
36→        lastValidBlockHeight,
37→      },
38→      "confirmed"
39→    );
40→
41→    if (confirmation.value.err) {
42→      console.error("[swap] Transaction error:", confirmation.value.err);
43→      return {
44→        success: false,
45→        error: SWAP_ERRORS.TRANSACTION_FAILED,
46→      };
47→    }
48→
49→    return {
50→      success: true,
51→      signature,
52→      fromAmount,
53→      fromSymbol,
54→      toAmount,
55→      toSymbol,
56→    };
57→  } catch (error) {
58→    console.error("[swap] Execution error:", error);
59→
60→    if (error instanceof Error) {
61→      if (error.message.includes("signature")) {
62→        return { success: false, error: SWAP_ERRORS.SIGNING_FAILED };
63→      }
64→      if (error.message.includes("timeout")) {
65→        return { success: false, error: SWAP_ERRORS.CONFIRMATION_TIMEOUT };
66→      }
67→    }
68→
69→    return {
70→      success: false,
71→      error: SWAP_ERRORS.TRANSACTION_FAILED,
72→    };
73→  }
74→}
