 5→export const topUpDeposit = async (
 6→  provider: AnchorProvider,
 7→  username: string,
 8→  amount: number
 9→) => {
10→  const transferProgram = getTelegramTransferProgram(provider);
11→  const userPublicKey = provider.wallet.publicKey;
12→  const amountBN = numberToBN(amount);
13→
14→  try {
15→    await transferProgram.methods
16→      .depositForUsername(username, amountBN)
17→      .accounts({
18→        payer: userPublicKey,
19→        depositor: userPublicKey,
20→      })
21→      .rpc({ commitment: "confirmed" });
22→    return true;
23→  } catch (error) {
24→    console.error("Failed to top up deposit", error);
25→    return false;
26→  }
27→};
