                    <p
                      className="text-[15px] leading-5 text-left"
                      style={{ color: "rgba(60, 60, 67, 0.6)" }}
                    >
                      ${token.priceUsd.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </p>
