import { useEffect, useState } from "react";

import { SOLANA_FEE_SOL } from "@/lib/constants";
import { estimateTransactionFeeSol } from "@/lib/solana/estimate-fee";

/**
 * Returns the estimated transaction fee in SOL.
 * Starts with the hardcoded constant, then updates with a network-based estimate.
 */
export function useEstimatedFee(): number {
  const [fee, setFee] = useState(SOLANA_FEE_SOL);

  useEffect(() => {
    estimateTransactionFeeSol().then(setFee);
  }, []);

  return fee;
}

