function holdingToToken(holding: TokenHolding): Token {
  return {
    symbol: holding.symbol,
    name: holding.name,
    icon: getTokenIcon(holding),
    decimals: holding.decimals,
    balance: holding.balance,
    priceUsd: holding.priceUsd ?? 0,
    mint: holding.mint,
    isSecured: holding.isSecured,
  };
}

