                      <Image src="/dogs/dog-cry.png" alt="Error" width={96} height={96} />
                    </div>
                    <div className="flex flex-col gap-2 items-center text-center max-w-[280px]">
                      <h2 className="text-xl font-semibold text-black leading-6">
