import { LAMPORTS_PER_SOL } from "@solana/web3.js";

import { getConnection } from "./rpc";

const BASE_FEE_LAMPORTS = 5000;
const DEFAULT_COMPUTE_UNITS = 200_000;
const CACHE_TTL_MS = 60_000;

let cachedFee: { lamports: number; timestamp: number } | null = null;

/**
 * Estimate the transaction fee in lamports using recent network priority fees.
 * Returns base fee (5000 lamports) + 75th percentile priority fee.
 * Results are cached for 60 seconds.
 */
export async function estimateTransactionFee(): Promise<number> {
  if (cachedFee && Date.now() - cachedFee.timestamp < CACHE_TTL_MS) {
    return cachedFee.lamports;
  }

  try {
    const connection = getConnection();
    const recentFees = await connection.getRecentPrioritizationFees();

    if (recentFees.length === 0) {
      return BASE_FEE_LAMPORTS;
    }

    const sorted = recentFees
      .map((f) => f.prioritizationFee)
      .sort((a, b) => a - b);
    const p75Index = Math.floor(sorted.length * 0.75);
    const priorityFeePerCU = sorted[p75Index];

    // microLamports per CU * CU / 1,000,000 = lamports
    const priorityFeeLamports = Math.ceil(
      (priorityFeePerCU * DEFAULT_COMPUTE_UNITS) / 1_000_000
    );

    const totalFee = BASE_FEE_LAMPORTS + priorityFeeLamports;
    cachedFee = { lamports: totalFee, timestamp: Date.now() };
    return totalFee;
  } catch {
    return BASE_FEE_LAMPORTS;
  }
}

/** Estimate transaction fee in SOL. Falls back to base fee on error. */
export async function estimateTransactionFeeSol(): Promise<number> {
  const lamports = await estimateTransactionFee();
  return lamports / LAMPORTS_PER_SOL;
}

