                  <p className="text-[15px] leading-5 text-black">
                    {rateDisplay}
                  </p>
                </div>
                {/* Slippage */}
                <div className="flex items-center justify-between">
                  <p
                    className="text-[15px] leading-5"
                    style={{ color: "rgba(60, 60, 67, 0.6)" }}
